import{_ as e,o as a,c as l,a4 as s}from"./chunks/framework._in6GHBg.js";const c=JSON.parse('{"title":"有机化学基础详解","description":"","frontmatter":{},"headers":[],"relativePath":"chemistry/Chem-Learn-Detail-004-有机化学详解-20260405.md","filePath":"chemistry/Chem-Learn-Detail-004-有机化学详解-20260405.md"}'),n={name:"chemistry/Chem-Learn-Detail-004-有机化学详解-20260405.md"};function i(r,t,o,d,g,p){return a(),l("div",null,[...t[0]||(t[0]=[s(`<h1 id="有机化学基础详解" tabindex="-1">有机化学基础详解 <a class="header-anchor" href="#有机化学基础详解" aria-label="Permalink to &quot;有机化学基础详解&quot;">​</a></h1><p><strong>板块4：烃类 + 烃的衍生物 + 有机推断（选考必考）</strong></p><hr><h2 id="学习策略" tabindex="-1">学习策略 <a class="header-anchor" href="#学习策略" aria-label="Permalink to &quot;学习策略&quot;">​</a></h2><p><strong>有机化学的核心是「官能团」</strong>：</p><ul><li>官能团决定性质</li><li>性质决定反应</li><li>反应决定转化关系</li></ul><p><strong>学习方法</strong>：</p><ol><li><strong>熟记官能团</strong>：名称、结构、性质、特征反应</li><li><strong>掌握转化关系</strong>：醇→醛→酸→酯的转化</li><li><strong>找突破口</strong>：推断题的特征现象、分子式、反应条件</li><li><strong>多画图</strong>：官能团转化关系网、同分异构体树状图</li></ol><hr><h2 id="第一章-烃类" tabindex="-1">第一章：烃类 <a class="header-anchor" href="#第一章-烃类" aria-label="Permalink to &quot;第一章：烃类&quot;">​</a></h2><h3 id="_1-1-烷烃" tabindex="-1">1.1 烷烃 <a class="header-anchor" href="#_1-1-烷烃" aria-label="Permalink to &quot;1.1 烷烃&quot;">​</a></h3><p><strong>通式</strong>：CₙH₂ₙ₊₂</p><p><strong>代表物</strong>：甲烷（CH₄）</p><p><strong>化学性质</strong>（稳定，取代反应为主）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CH₄ + Cl₂ → CH₃Cl + HCl（光照条件，连锁反应）</span></span></code></pre></div><p><strong>特点</strong>：</p><ul><li>不能使溴水褪色</li><li>不能使KMnO₄褪色</li><li>取代反应，产物混合物</li></ul><h3 id="_1-2-烯烃" tabindex="-1">1.2 烯烃 <a class="header-anchor" href="#_1-2-烯烃" aria-label="Permalink to &quot;1.2 烯烃&quot;">​</a></h3><p><strong>通式</strong>：CₙH₂ₙ</p><p><strong>代表物</strong>：乙烯（CH₂=CH₂）</p><p><strong>官能团</strong>：碳碳双键（C=C）</p><p><strong>化学性质</strong>（活泼，加成反应为主）：</p><p><strong>1. 加成反应</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CH₂=CH₂ + Br₂ → CH₂Br-CH₂Br（使溴水褪色）</span></span>
<span class="line"><span>CH₂=CH₂ + H₂ → CH₃-CH₃（催化加氢）</span></span>
<span class="line"><span>CH₂=CH₂ + H₂O → CH₃-CH₂OH（水化制乙醇）</span></span></code></pre></div><p><strong>2. 氧化反应</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CH₂=CH₂ + 3O₂ → 2CO₂ + 2H₂O（燃烧）</span></span>
<span class="line"><span>5CH₂=CH₂ + 12KMnO₄ + 18H₂SO₄ → ...（使KMnO₄褪色）</span></span></code></pre></div><p><strong>3. 加聚反应</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>nCH₂=CH₂ → [CH₂-CH₂]n（聚乙烯）</span></span></code></pre></div><p><strong>特征反应</strong>：能使溴水、KMnO₄溶液褪色（检验烯烃）</p><h3 id="_1-3-炔烃" tabindex="-1">1.3 炔烃 <a class="header-anchor" href="#_1-3-炔烃" aria-label="Permalink to &quot;1.3 炔烃&quot;">​</a></h3><p><strong>通式</strong>：CₙH₂ₙ₋₂</p><p><strong>代表物</strong>：乙炔（CH≡CH）</p><p><strong>官能团</strong>：碳碳三键（C≡C）</p><p><strong>化学性质</strong>：与烯烃类似，能加成、氧化、加聚</p><h3 id="_1-4-芳香烃" tabindex="-1">1.4 芳香烃 <a class="header-anchor" href="#_1-4-芳香烃" aria-label="Permalink to &quot;1.4 芳香烃&quot;">​</a></h3><p><strong>代表物</strong>：苯（C₆H₆）</p><p><strong>结构特点</strong>：平面正六边形，碳碳键介于单双键之间</p><p><strong>化学性质</strong>（稳定，特殊结构）：</p><p><strong>1. 取代反应</strong>（不是加成）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>C₆H₆ + Br₂ → C₆H₅Br + HBr（FeBr₃催化）</span></span>
<span class="line"><span>C₆H₆ + HNO₃ → C₆H₅NO₂ + H₂O（浓H₂SO₄，加热）</span></span></code></pre></div><p><strong>2. 加成反应</strong>（需催化剂、加热）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>C₆H₆ + 3H₂ → C₆H₁₂（环己烷，Ni催化）</span></span></code></pre></div><p><strong>注意</strong>：苯不能使溴水褪色（萃取除外），不能使KMnO₄褪色。</p><hr><h2 id="第二章-烃的衍生物" tabindex="-1">第二章：烃的衍生物 <a class="header-anchor" href="#第二章-烃的衍生物" aria-label="Permalink to &quot;第二章：烃的衍生物&quot;">​</a></h2><h3 id="_2-1-官能团速查表" tabindex="-1">2.1 官能团速查表 <a class="header-anchor" href="#_2-1-官能团速查表" aria-label="Permalink to &quot;2.1 官能团速查表&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">类别</th><th style="text-align:center;">官能团</th><th style="text-align:center;">代表物</th><th style="text-align:left;">特征反应</th></tr></thead><tbody><tr><td style="text-align:center;">卤代烃</td><td style="text-align:center;">-X（Cl、Br）</td><td style="text-align:center;">CH₃CH₂Cl</td><td style="text-align:left;">水解、消去</td></tr><tr><td style="text-align:center;"><strong>醇</strong></td><td style="text-align:center;"><strong>-OH</strong>（羟基）</td><td style="text-align:center;">CH₃CH₂OH</td><td style="text-align:left;">与Na反应、氧化、酯化</td></tr><tr><td style="text-align:center;"><strong>酚</strong></td><td style="text-align:center;"><strong>-OH</strong>（直接连苯环）</td><td style="text-align:center;">C₆H₅OH</td><td style="text-align:left;">弱酸性、与FeCl₃显色</td></tr><tr><td style="text-align:center;"><strong>醛</strong></td><td style="text-align:center;"><strong>-CHO</strong>（醛基）</td><td style="text-align:center;">CH₃CHO</td><td style="text-align:left;">银镜反应、与新制Cu(OH)₂反应</td></tr><tr><td style="text-align:center;"><strong>酮</strong></td><td style="text-align:center;"><strong>-CO-</strong>（羰基）</td><td style="text-align:center;">CH₃COCH₃</td><td style="text-align:left;">加成反应</td></tr><tr><td style="text-align:center;"><strong>羧酸</strong></td><td style="text-align:center;"><strong>-COOH</strong>（羧基）</td><td style="text-align:center;">CH₃COOH</td><td style="text-align:left;">酸性、酯化</td></tr><tr><td style="text-align:center;"><strong>酯</strong></td><td style="text-align:center;"><strong>-COO-</strong>（酯基）</td><td style="text-align:center;">CH₃COOCH₂CH₃</td><td style="text-align:left;">水解</td></tr></tbody></table><h3 id="_2-2-醇-重点" tabindex="-1">2.2 醇（重点） <a class="header-anchor" href="#_2-2-醇-重点" aria-label="Permalink to &quot;2.2 醇（重点）&quot;">​</a></h3><p><strong>代表物</strong>：乙醇（CH₃CH₂OH）</p><p><strong>化学性质</strong>：</p><p><strong>1. 与活泼金属反应</strong>（如Na）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2CH₃CH₂OH + 2Na → 2CH₃CH₂ONa + H₂↑</span></span></code></pre></div><p><strong>2. 氧化反应</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2CH₃CH₂OH + O₂ → 2CH₃CHO + 2H₂O（Cu/Ag催化，生成醛）</span></span></code></pre></div><p><strong>3. 消去反应</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CH₃CH₂OH → CH₂=CH₂ + H₂O（浓H₂SO₄，170℃）</span></span></code></pre></div><p><strong>4. 酯化反应</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CH₃COOH + CH₃CH₂OH ⇌ CH₃COOCH₂CH₃ + H₂O（浓H₂SO₄，加热）</span></span></code></pre></div><h3 id="_2-3-醛-重点-检验特征明显" tabindex="-1">2.3 醛（重点，检验特征明显） <a class="header-anchor" href="#_2-3-醛-重点-检验特征明显" aria-label="Permalink to &quot;2.3 醛（重点，检验特征明显）&quot;">​</a></h3><p><strong>代表物</strong>：乙醛（CH₃CHO）</p><p><strong>特征反应</strong>（检验醛基）：</p><p><strong>1. 银镜反应</strong>（与银氨溶液）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CH₃CHO + 2[Ag(NH₃)₂]OH → CH₃COONH₄ + 2Ag↓ + 3NH₃ + H₂O</span></span></code></pre></div><ul><li>现象：试管内壁形成光亮银镜</li><li>条件：水浴加热</li></ul><p><strong>2. 与新制Cu(OH)₂反应</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CH₃CHO + 2Cu(OH)₂ + NaOH → CH₃COONa + Cu₂O↓ + 3H₂O</span></span></code></pre></div><ul><li>现象：生成砖红色沉淀（Cu₂O）</li><li>条件：加热至沸腾</li></ul><h3 id="_2-4-羧酸和酯" tabindex="-1">2.4 羧酸和酯 <a class="header-anchor" href="#_2-4-羧酸和酯" aria-label="Permalink to &quot;2.4 羧酸和酯&quot;">​</a></h3><p><strong>羧酸代表物</strong>：乙酸（CH₃COOH，醋酸）</p><p><strong>性质</strong>：</p><ul><li>弱酸性：CH₃COOH ⇌ CH₃COO⁻ + H⁺</li><li>酯化反应（见上文）</li></ul><p><strong>酯代表物</strong>：乙酸乙酯（CH₃COOCH₂CH₃）</p><p><strong>性质</strong>：水解反应</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CH₃COOCH₂CH₃ + H₂O ⇌ CH₃COOH + CH₃CH₂OH（酸性条件）</span></span>
<span class="line"><span>CH₃COOCH₂CH₃ + NaOH → CH₃COONa + CH₃CH₂OH（碱性条件，皂化）</span></span></code></pre></div><hr><h2 id="第三章-有机反应类型总结" tabindex="-1">第三章：有机反应类型总结 <a class="header-anchor" href="#第三章-有机反应类型总结" aria-label="Permalink to &quot;第三章：有机反应类型总结&quot;">​</a></h2><h3 id="_3-1-反应类型速查" tabindex="-1">3.1 反应类型速查 <a class="header-anchor" href="#_3-1-反应类型速查" aria-label="Permalink to &quot;3.1 反应类型速查&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">反应类型</th><th style="text-align:left;">特点</th><th style="text-align:left;">典型例子</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>取代反应</strong></td><td style="text-align:left;">原子或基团被替代</td><td style="text-align:left;">烷烃卤代、苯的硝化、酯化、水解</td></tr><tr><td style="text-align:left;"><strong>加成反应</strong></td><td style="text-align:left;">不饱和键断裂，加上原子或基团</td><td style="text-align:left;">烯烃加Br₂、加H₂、加H₂O</td></tr><tr><td style="text-align:left;"><strong>消去反应</strong></td><td style="text-align:left;">从分子中消去小分子（H₂O、HX）</td><td style="text-align:left;">醇消去生成烯烃</td></tr><tr><td style="text-align:left;"><strong>氧化反应</strong></td><td style="text-align:left;">加氧或去氢</td><td style="text-align:left;">醇→醛→酸、烯烃使KMnO₄褪色</td></tr><tr><td style="text-align:left;"><strong>还原反应</strong></td><td style="text-align:left;">加氢或去氧</td><td style="text-align:left;">醛→醇、烯烃加氢</td></tr><tr><td style="text-align:left;"><strong>加聚反应</strong></td><td style="text-align:left;">不饱和化合物聚合成高分子</td><td style="text-align:left;">乙烯→聚乙烯</td></tr><tr><td style="text-align:left;"><strong>缩聚反应</strong></td><td style="text-align:left;">单体间脱去小分子聚合</td><td style="text-align:left;">氨基酸→蛋白质</td></tr></tbody></table><h3 id="_3-2-反应条件与反应类型对应" tabindex="-1">3.2 反应条件与反应类型对应 <a class="header-anchor" href="#_3-2-反应条件与反应类型对应" aria-label="Permalink to &quot;3.2 反应条件与反应类型对应&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">反应条件</th><th style="text-align:left;">可能的反应类型</th></tr></thead><tbody><tr><td style="text-align:left;">光照</td><td style="text-align:left;">烷烃卤代（取代）</td></tr><tr><td style="text-align:left;">浓H₂SO₄，170℃</td><td style="text-align:left;">醇消去</td></tr><tr><td style="text-align:left;">浓H₂SO₄，加热</td><td style="text-align:left;">酯化、硝化、磺化（取代）</td></tr><tr><td style="text-align:left;">NaOH水溶液，加热</td><td style="text-align:left;">卤代烃水解、酯水解</td></tr><tr><td style="text-align:left;">NaOH醇溶液，加热</td><td style="text-align:left;">卤代烃消去</td></tr><tr><td style="text-align:left;">Cu/Ag，加热</td><td style="text-align:left;">醇氧化成醛</td></tr><tr><td style="text-align:left;">Ni，加热</td><td style="text-align:left;">烯烃/醛/酮加氢（还原）</td></tr><tr><td style="text-align:left;">银氨溶液，水浴</td><td style="text-align:left;">醛基氧化（银镜反应）</td></tr><tr><td style="text-align:left;">新制Cu(OH)₂，加热</td><td style="text-align:left;">醛基氧化</td></tr></tbody></table><hr><h2 id="第四章-有机推断题攻略" tabindex="-1">第四章：有机推断题攻略 <a class="header-anchor" href="#第四章-有机推断题攻略" aria-label="Permalink to &quot;第四章：有机推断题攻略&quot;">​</a></h2><h3 id="_4-1-突破口总结" tabindex="-1">4.1 突破口总结 <a class="header-anchor" href="#_4-1-突破口总结" aria-label="Permalink to &quot;4.1 突破口总结&quot;">​</a></h3><p><strong>1. 特征现象突破口</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">现象</th><th style="text-align:left;">推断</th></tr></thead><tbody><tr><td style="text-align:left;">使溴水褪色</td><td style="text-align:left;">含C=C、C≡C或醛基</td></tr><tr><td style="text-align:left;">使KMnO₄褪色</td><td style="text-align:left;">含C=C、C≡C、醛基或苯的同系物</td></tr><tr><td style="text-align:left;">银镜反应</td><td style="text-align:left;">含醛基（-CHO）</td></tr><tr><td style="text-align:left;">与FeCl₃显紫色</td><td style="text-align:left;">含酚羟基</td></tr><tr><td style="text-align:left;">与Na反应放出H₂</td><td style="text-align:left;">含-OH或-COOH</td></tr><tr><td style="text-align:left;">与Na₂CO₃/NaHCO₃反应放出CO₂</td><td style="text-align:left;">含-COOH</td></tr></tbody></table><p><strong>2. 分子式突破口</strong></p><ul><li>计算不饱和度：Ω = (2C + 2 + N - H - X)/2</li><li>Ω=0：饱和化合物（烷烃、醇、醚）</li><li>Ω=1：含一个双键或一个环（烯烃、酮、醛）</li><li>Ω=2：含两个双键或一个三键或一个双键+一个环</li><li>Ω=4：可能含苯环</li></ul><p><strong>3. 反应条件突破口</strong></p><ul><li>见上文「反应条件与反应类型对应」</li></ul><p><strong>4. 转化关系突破口</strong></p><p>常见转化链：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>醇 → 醛 → 羧酸 → 酯</span></span>
<span class="line"><span>↑              ↓</span></span>
<span class="line"><span>└── 水解 ────────┘</span></span></code></pre></div><h3 id="_4-2-有机推断题解题步骤" tabindex="-1">4.2 有机推断题解题步骤 <a class="header-anchor" href="#_4-2-有机推断题解题步骤" aria-label="Permalink to &quot;4.2 有机推断题解题步骤&quot;">​</a></h3><ol><li><strong>审题</strong>：找出分子式、反应条件、特征现象</li><li><strong>算不饱和度</strong>：推测可能结构</li><li><strong>找突破口</strong>：从特征现象或条件入手</li><li><strong>顺藤摸瓜</strong>：根据转化关系推导其他物质</li><li><strong>验证</strong>：检查是否符合所有条件</li></ol><h3 id="_4-3-同分异构体书写" tabindex="-1">4.3 同分异构体书写 <a class="header-anchor" href="#_4-3-同分异构体书写" aria-label="Permalink to &quot;4.3 同分异构体书写&quot;">​</a></h3><p><strong>步骤</strong>：</p><ol><li><strong>写碳链异构</strong>：主链由长到短</li><li><strong>写位置异构</strong>：官能团位置变化</li><li><strong>写官能团异构</strong>：不同官能团（如醇和醚）</li></ol><p><strong>例子</strong>：C₄H₁₀O的同分异构体（醇和醚）</p><ul><li>醇：CH₃CH₂CH₂CH₂OH、CH₃CH₂CH(OH)CH₃、(CH₃)₂CHCH₂OH、(CH₃)₃COH</li><li>醚：CH₃OCH₂CH₂CH₃、CH₃CH₂OCH₂CH₃、CH₃OCH(CH₃)₂</li></ul><hr><h2 id="faq-常见错误与解答" tabindex="-1">FAQ（常见错误与解答） <a class="header-anchor" href="#faq-常见错误与解答" aria-label="Permalink to &quot;FAQ（常见错误与解答）&quot;">​</a></h2><h3 id="q1-官能团性质太多记不住怎么办" tabindex="-1">Q1：官能团性质太多记不住怎么办？ <a class="header-anchor" href="#q1-官能团性质太多记不住怎么办" aria-label="Permalink to &quot;Q1：官能团性质太多记不住怎么办？&quot;">​</a></h3><p><strong>A</strong>：重点记「特征反应」：</p><ul><li>能发生银镜反应的：醛基</li><li>能使溴水褪色的：C=C、C≡C、醛基</li><li>能与Na反应放H₂的：-OH、-COOH</li><li>与FeCl₃显色的：酚羟基</li></ul><p>其他性质通过官能团推断（如含-OH的能发生酯化）。</p><h3 id="q2-有机推断题总是推不出来怎么办" tabindex="-1">Q2：有机推断题总是推不出来怎么办？ <a class="header-anchor" href="#q2-有机推断题总是推不出来怎么办" aria-label="Permalink to &quot;Q2：有机推断题总是推不出来怎么办？&quot;">​</a></h3><p><strong>A</strong>：</p><ol><li>先熟记「转化关系图」（醇-醛-酸-酯）</li><li>记住常见「突破口」（特征现象、分子式、反应条件）</li><li>多做题，总结每道题的突破口是怎么用的</li><li>画推断流程图，不要空想</li></ol><h3 id="q3-同分异构体总是数漏或重复怎么办" tabindex="-1">Q3：同分异构体总是数漏或重复怎么办？ <a class="header-anchor" href="#q3-同分异构体总是数漏或重复怎么办" aria-label="Permalink to &quot;Q3：同分异构体总是数漏或重复怎么办？&quot;">​</a></h3><p><strong>A</strong>：</p><ol><li>按步骤来：先碳链异构，再位置异构，最后官能团异构</li><li>用「等效氢法」确定一元取代物数目</li><li>写出来后用系统命名法验证（命名相同就是重复）</li><li>记住常见数目（如C₄H₉-有4种，C₅H₁₁-有8种）</li></ol><h3 id="q4-酯化反应方程式总是写错怎么办" tabindex="-1">Q4：酯化反应方程式总是写错怎么办？ <a class="header-anchor" href="#q4-酯化反应方程式总是写错怎么办" aria-label="Permalink to &quot;Q4：酯化反应方程式总是写错怎么办？&quot;">​</a></h3><p><strong>A</strong>：</p><ul><li>记住「酸脱羟基，醇脱氢」</li><li>可逆号，浓H₂SO₄作催化剂和吸水剂</li><li>产物是酯和水，不要漏写水</li></ul><hr><h2 id="文档信息" tabindex="-1">文档信息 <a class="header-anchor" href="#文档信息" aria-label="Permalink to &quot;文档信息&quot;">​</a></h2><p><strong>文档编号</strong>: Chem-Learn-Detail-004<br><strong>板块</strong>: 有机化学基础<br><strong>版本</strong>: V1.0<br><strong>编制日期</strong>: 2026-04-05<br><strong>配套文档</strong>: Chem-Learn-Method-001</p><hr><p><em>有机化学是「结构决定性质」的最好体现，抓住官能团就抓住了一切。</em></p>`,119)])])}const C=e(n,[["render",i]]);export{c as __pageData,C as default};
